use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $text = '';
    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->page($page);
        $text .= $page_obj->text;
    }

    return $text;
}

# Function to extract specific information
sub extract_info {
    my ($text) = @_;
    my $info = {};

    # Example extraction logic
    if ($text =~ /Date:\s*(\d{1,2}\/\d{1,2}\/\d{4})/) {
        $info->{date} = $1;
    }
    if ($text =~ /Author:\s*(\w+)/) {
        $info->{author} = $1;
    }
    if ($text =~ /Table\s+\d+\.\s*(.+)/) {
        $info->{table} = $1;
    }

    return $info;
}

# Main script
my $pdf_file = 'example.pdf'; # Replace with your PDF file path
